import{_ as l,p as i,q as a,a1 as t}from"./framework-822ca1a4.js";const d={},e=t('<h1 id="第-1-单元总结" tabindex="-1"><a class="header-anchor" href="#第-1-单元总结" aria-hidden="true">#</a> 第 1 单元总结</h1><h2 id="は-です" tabindex="-1"><a class="header-anchor" href="#は-です" aria-hidden="true">#</a> ～は～です</h2><p>肯定的判断句，相当于汉语的“~是~”。“～は”是主语部分，“～です”是谓语部分。助词“は”用于提示主题，读作“わ”。</p><ul><li>わたしは中国人です。</li><li>わたしはりです。</li></ul><h2 id="は-ではありません" tabindex="-1"><a class="header-anchor" href="#は-ではありません" aria-hidden="true">#</a> ～は～ではありません</h2><p>否定的判断句，相当于汉语的“~不是~”。“ではありません”的“では”，在日语口语中有时候会变成“じゃ”。</p><ul><li>森さんは課長ではありません。</li><li>わたしは日本人じやありません。</li></ul><h2 id="は-ですか" tabindex="-1"><a class="header-anchor" href="#は-ですか" aria-hidden="true">#</a> ～は～ですか</h2><p>疑问句，相当于汉语“~是~吗？”。助词“か”接在句尾表示疑问。日语的问句在句尾不用使用“？”。回答时用“はい”或者“いいえ”。不知道时使用“分かりません”。</p><ul><li><p>李さんは中国人ですか。</p><p>はい、李さんは中国人です。</p><p>はい、そうです。</p></li><li><p>李さんは日本人ですか。</p><p>いいえ、日本人ではありません。</p><p>いいえ、ちがいます。中国人です。</p></li></ul><h2 id="の" tabindex="-1"><a class="header-anchor" href="#の" aria-hidden="true">#</a> ～の～</h2><p>助词“の”连接名词和名词，表示前面的名词是后面的名词从属的机构、国家或属性。</p><ul><li>李さんは JC 企画の社員です。</li><li>わたしは日本人の留学生ではありません。</li><li>ヂュポンさんは大学の先生ですか。</li><li>これはわたしのかぎです。</li><li>あれは家族の写真です。</li></ul><h2 id="こ-そ-あ-ど" tabindex="-1"><a class="header-anchor" href="#こ-そ-あ-ど" aria-hidden="true">#</a> こ/そ/あ/ど</h2><table><thead><tr><th></th><th>こ</th><th>そ</th><th>あ</th><th>ど</th></tr></thead><tbody><tr><td>物</td><td>これ</td><td>それ</td><td>あれ</td><td>どれ</td></tr><tr><td>连体词</td><td>この</td><td>その</td><td>あの</td><td>どの</td></tr><tr><td>场所</td><td>ここ</td><td>そこ</td><td>あそこ</td><td>どこ</td></tr><tr><td>场所(郑重场合)<br>方向</td><td>こちら</td><td>そちら</td><td>あちら</td><td>どちら</td></tr></tbody></table><p>指示代词，“こ/そ/あ/ど”分别表示汉语“这/那/那/哪”，在日语中多了一个“そ”，介于“こ”和“あ”中间的位置。指示代词的用法表较多，下面分开讲。</p><ol><li>表示方向</li></ol><ul><li><p>こちれへどうぞ。</p></li><li><p>それは何ですか。</p><p>これはカメラです。</p></li><li><p>李さんの本はどの本ですか。</p><p>そのです。</p></li><li><p>田中さんのかばんはどれですか</p><p>あれです。</p></li></ul><ol start="2"><li>表示地点</li></ol><ul><li>ここ/そこ/あそこは学園です。</li><li>こちら/そちら/あちらは学園です。</li></ul><ol start="3"><li>敬称</li></ol><ul><li>そちらは田中です。</li></ul><h2 id="は-です-1" tabindex="-1"><a class="header-anchor" href="#は-です-1" aria-hidden="true">#</a> ～は～です</h2><p>表示“名词”存在于“场所”。</p><ul><li>李さんはトイレです。</li></ul><h2 id="も" tabindex="-1"><a class="header-anchor" href="#も" aria-hidden="true">#</a> ～も～</h2><p>相当于汉语中的“也”。</p><ul><li><p>わたしは中国人です。あなたも中国人ですか。</p><p>はい、中国人です。</p><p>いいえ、わたしは中国人ではありません。日本人です。</p></li></ul><h2 id="は-ですか、-ですか" tabindex="-1"><a class="header-anchor" href="#は-ですか、-ですか" aria-hidden="true">#</a> ～は～ですか、～ですか</h2><p>选择疑问句，可以有两个或多个组成。</p><ul><li><p>今日は水曜日ですか、木曜日ですか。</p><p>今日は木曜日です。</p></li></ul><h2 id="に-があります-います" tabindex="-1"><a class="header-anchor" href="#に-があります-います" aria-hidden="true">#</a> ～に～があります/います</h2><p>存在句，相当于汉语中的“~有~”。“あります”表示无生命的事物，“います”表示有生命的事物。</p><ul><li>部屋に机があります。</li><li>部屋に猫がいます。</li></ul><h2 id="は-にあります-います" tabindex="-1"><a class="header-anchor" href="#は-にあります-います" aria-hidden="true">#</a> ～は～にあります/います</h2><p>所在句，相当于汉语中的“~在~”。</p><ul><li>いすは部屋にあります。</li><li>子供は公園にいます。</li></ul><h2 id="あります-います-对应的疑问句" tabindex="-1"><a class="header-anchor" href="#あります-います-对应的疑问句" aria-hidden="true">#</a> あります/います 对应的疑问句</h2><ol><li>不含疑问词</li></ol><ul><li><p>本はいすの上にあります。</p><p>はい、あります</p><p>いいえ、ありません</p></li></ul><ol start="2"><li>含疑问词</li></ol><ul><li>テレビの上に何がありますか。</li><li>会議室にだりがいますか。</li><li>スミスさんの家はどこにありますか。</li></ul><h2 id="と" tabindex="-1"><a class="header-anchor" href="#と" aria-hidden="true">#</a> ～と～</h2><p>并列句，相当于汉语中的“也”。可以并列两个或多个。</p><ul><li><p>箱の中に何があありますか。</p><p>時計と眼鏡があります。</p></li></ul><h2 id="疑问词-も-否定" tabindex="-1"><a class="header-anchor" href="#疑问词-も-否定" aria-hidden="true">#</a> 疑问词 + も + 否定</h2><p>表示全面否定。</p><ul><li><p>教室にだれがいますか。</p><p>だれもいません。</p></li><li><p>箱の中に何があありますか。</p><p>何もありもせん。</p></li></ul>',48),h=[e];function r(p,n){return i(),a("div",null,h)}const s=l(d,[["render",r],["__file","unit4-1.html.vue"]]);export{s as default};
